  let rwphPayAllActiveScope = null;
  let rwphPayAllLastMemberField = null;

  function rwphPayAllFieldScope(el) {
    if (!el || !el.closest) return null;
    const selectors = [
      "form",
      "[role='dialog']",
      "[aria-modal='true']",
      "[class*='modal']",
      "[class*='popup']",
      "[class*='dialog']",
      "[class*='money']",
      "[class*='bank']",
      "[class*='payment']",
      "[class*='pay']",
      "[class*='send']",
      "[class*='give']",
      "[class*='transfer']",
      "section",
      "article",
      "main"
    ].join(",");
    const scope = el.closest(selectors);
    return (scope && scope !== document.body && scope !== document.documentElement) ? scope : null;
  }

  function rwphPayAllFieldsInScope(scope) {
    const root = scope && scope.querySelectorAll ? scope : document;
    return Array.from(root.querySelectorAll("input, textarea, [contenteditable='true'], [role='textbox'], [role='spinbutton']"))
      .filter(rwphSendHelperVisible)
      .filter((el) => !el.disabled && !el.readOnly && el.getAttribute?.("aria-disabled") !== "true")
      .filter((el) => !el.closest?.("#rw-pay-all-panel, #rw-payout-helper, #rwph-xanax-send-status, .rw-pay-all-panel"))
      .filter((el) => {
        const type = String(el.type || "").toLowerCase();
        return !["hidden", "button", "submit", "reset", "checkbox", "radio", "file", "image", "password"].includes(type);
      });
  }

  function renderPayAllCopyPanelHtml(rows) {
    const safeRows = rows || [];
    return `
      <div id="rw-pay-all-panel" class="rw-pay-all-panel" hidden>
        <button type="button" class="danger rw-pay-all-close" data-pay-all-close="1">×</button>
        <div class="rw-pay-all-head">
          <div class="rw-pay-all-title">Payments Copy Panel</div>
        </div>
        <div class="rw-pay-all-note">Use this helper inside Torn faction controls. It is a payout checklist, not an automatic payment sender.</div>
        <div class="rw-pay-all-info">
          <b>How to use:</b>
          <ul>
            <li><b>Name + ID</b> copies/prefills the member.</li>
            <li><b>Amount</b> copies/prefills the payout money.</li>
            <li>Buttons disappear after one click so you can track progress.</li>
            <li>Use <b>Bring Back Disappeared Button</b> to bring back only the most recently hidden button.</li>
            <li>Open the correct add money/banking fields first. If Torn hides the amount field until a member is selected, press Name + ID first, then press Amount.</li>
            <li>You manually review and confirm every payment in Torn.</li>
          </ul>
        </div>
        <button type="button" class="secondary rw-pay-all-undo" data-pay-all-undo="1">Bring Back Disappeared Button</button>
        <div class="rw-pay-all-list">
          ${safeRows.map((r, index) => {
            const name = r.name || `Unknown ${r.id || "unknown"}`;
            const id = String(r.id || "unknown");
            const payout = rwphPayAllRowAmount(r);
            return `
              <div class="rw-pay-all-row">
                <div class="rw-pay-all-member">${index + 1}. ${esc(name)} [${esc(id)}]<span class="rw-pay-all-payout">${money(payout)}</span></div>
                <button type="button" class="secondary rw-pay-all-copy" data-pay-copy-name="${index}">Name + ID</button>
                <button type="button" class="secondary rw-pay-all-copy" data-pay-copy-amount="${index}">Amount</button>
              </div>`;
          }).join("") || `<div class="rw-pay-all-row"><div class="rw-pay-all-member">No payable members found.</div></div>`}
        </div>
      </div>`;
  }

  function closePayAllCopyPanel() {
    const existing = document.getElementById("rw-pay-all-panel");
    if (existing) existing.remove();
  }

  function rwphPayAllFieldMeta(el) {
    if (!el) return "";
    const attrs = ["id", "class", "name", "placeholder", "aria-label", "title", "data-name", "data-id", "type", "role"];
    const attrText = attrs.map((a) => String(el.getAttribute?.(a) || "")).join(" ");
    const wrap = rwphSendHelperText(el.closest?.("label, div, li, tr, td, section, form") || el.parentElement || el);
    return `${attrText} ${wrap}`.replace(/\s+/g, " ").toLowerCase();
  }

  function rwphPayAllEditableFields(scope = null) {
    return rwphPayAllFieldsInScope(scope || document);
  }


  function rwphFindPayAllMemberField() {
    const fields = rwphPayAllEditableFields();
    const scored = fields.map((el) => {
      const meta = rwphPayAllFieldMeta(el);
      let score = 0;
      if (/\b(user|player|member|recipient|name|id|torn)\b/.test(meta)) score += 8;
      if (/\b(to|add|target|search)\b/.test(meta)) score += 2;
      if ((el.tagName || "").toLowerCase() === "input" && ["text", "search", ""].includes(String(el.type || "").toLowerCase())) score += 2;
      if (/\b(amount|money|cash|balance|dollar|qty|quantity|message|comment|reason|note)\b/.test(meta)) score -= 12;
      return { el, score };
    }).filter((x) => x.score > 0).sort((a, b) => b.score - a.score);

    return scored[0]?.el || fields.find((el) => {
      const meta = rwphPayAllFieldMeta(el);
      return !/\b(amount|money|cash|balance|dollar|qty|quantity|message|comment|reason|note)\b/.test(meta) && String(el.type || "").toLowerCase() !== "number";
    }) || null;
  }

  function rwphFindPayAllAmountField(scope = null) {
    const scopedFields = scope ? rwphPayAllEditableFields(scope) : [];
    const fields = scopedFields.length ? scopedFields : rwphPayAllEditableFields();
    const amountRe = /\b(amount|money|cash|balance|dollar|payout|payment|pay|value|funds|give|transfer|deposit|send|add\s*money|add\s*to\s*balance)\b/;
    const hardNoRe = /\b(message|comment|reason|note|search|filter|api|key|code)\b/;
    const memberRe = /\b(user|player|member|recipient|username|profile|name|id|torn)\b/;

    const fieldTypeScore = (el) => {
      const type = String(el.type || "").toLowerCase();
      const inputMode = String(el.getAttribute?.("inputmode") || "").toLowerCase();
      let score = 0;
      if (["number", "tel"].includes(type)) score += 10;
      if (/\b(numeric|decimal)\b/.test(inputMode)) score += 8;
      if (el.getAttribute?.("role") === "spinbutton") score += 6;
      if ((el.tagName || "").toLowerCase() === "input" && ["text", "", "tel", "number"].includes(type)) score += 2;
      return score;
    };

    // Best case: Torn exposes useful field text, name, id, placeholder, type, role, or inputmode.
    // When Name + ID was clicked first, prefer amount-like fields after that current member field.
    const memberIndex = rwphPayAllLastMemberField ? fields.indexOf(rwphPayAllLastMemberField) : -1;
    const scored = fields.map((el, index) => {
      const meta = rwphPayAllFieldMeta(el);
      const hasAmountWords = amountRe.test(meta) || /[$]/.test(meta);
      let score = fieldTypeScore(el);
      if (hasAmountWords) score += 18;
      if (/\b(add\s*money|add\s*to\s*balance|give|transfer|deposit|send|payment|payout)\b/.test(meta)) score += 8;
      if (/[$]/.test(meta)) score += 5;
      // Do not reject an amount field just because the surrounding Torn form also contains member text.
      // Only penalize member/search words when the field has no money/amount clues.
      if (memberRe.test(meta) && !hasAmountWords) score -= 18;
      if (hardNoRe.test(meta) && !hasAmountWords) score -= 20;
      if (memberIndex >= 0) {
        if (index > memberIndex) score += 6;
        else score -= 10;
        score -= Math.min(Math.abs(index - memberIndex), 20) * 0.02;
      } else {
        score += Math.min(index, 8) * 0.05;
      }
      return { el, score, meta, hasAmountWords };
    }).filter((x) => x.score > 0).sort((a, b) => b.score - a.score);

    if (scored[0]?.el) return scored[0].el;

    const numeric = fields.find((el) => {
      const meta = rwphPayAllFieldMeta(el);
      const typeScore = fieldTypeScore(el);
      if (!typeScore) return false;
      return !hardNoRe.test(meta) && !/\b(search|filter|message|comment|reason|note)\b/.test(meta);
    });
    if (numeric) return numeric;

    // Last-resort Torn fallback: after the current member field is visible, use the next editable field in the same active payment form.
    const memberField = rwphPayAllLastMemberField && rwphSendHelperVisible(rwphPayAllLastMemberField)
      ? rwphPayAllLastMemberField
      : rwphFindPayAllMemberField();
    const startIndex = memberField ? fields.indexOf(memberField) + 1 : 0;
    const afterMember = fields.slice(Math.max(0, startIndex)).find((el) => {
      const meta = rwphPayAllFieldMeta(el);
      const type = String(el.type || "").toLowerCase();
      if (["search", "email", "url"].includes(type)) return false;
      if (hardNoRe.test(meta)) return false;
      if (amountRe.test(meta) || fieldTypeScore(el) > 0) return true;
      return !memberRe.test(meta);
    });
    return afterMember || null;
  }


  function rwphIsTouchPhoneOrPda() {
    try {
      return !!(window.matchMedia?.("(max-width: 760px), (pointer: coarse)")?.matches || /Android|iPhone|iPad|iPod|Mobile|TornPDA|Torn PDA/i.test(navigator.userAgent || ""));
    } catch (_) {
      return false;
    }
  }

  function rwphSetPayAllFieldValue(el, value) {
    if (!el) return false;

    const text = String(value ?? "");
    const touchMode = rwphIsTouchPhoneOrPda();

    // On Torn PDA/phones, focusing Torn's payment fields opens the software keypad.
    // For the Payments Copy Panel we set values silently and blur afterwards, so copy/prefill buttons stay fast.
    if (el.getAttribute?.("contenteditable") === "true" || el.getAttribute?.("role") === "textbox") {
      if (!touchMode) return rwphSetContentEditable(el, text);
      try {
        el.textContent = text;
        el.dispatchEvent(new InputEvent("input", { bubbles: true, cancelable: true, data: text, inputType: "insertText" }));
        el.dispatchEvent(new Event("change", { bubbles: true }));
        el.dispatchEvent(new Event("blur", { bubbles: true }));
        el.blur?.();
        document.activeElement?.blur?.();
        return true;
      } catch (_) {
        return false;
      }
    }

    let oldReadOnly;
    let hadReadOnly = false;
    let oldInputMode;
    if (touchMode) {
      try {
        oldReadOnly = el.readOnly;
        hadReadOnly = el.hasAttribute?.("readonly") || false;
        oldInputMode = el.getAttribute?.("inputmode");
        el.setAttribute?.("inputmode", "none");
        // Keep the field from summoning the keypad if the browser focuses it because of Torn handlers.
        try { el.readOnly = true; } catch (_) {}
      } catch (_) {}
    } else {
      el.focus?.({ preventScroll: true });
      el.click?.();
    }

    try {
      const proto = el instanceof HTMLTextAreaElement ? HTMLTextAreaElement.prototype : HTMLInputElement.prototype;
      const desc = Object.getOwnPropertyDescriptor(proto, "value");
      if (desc?.set) desc.set.call(el, text);
      else el.value = text;
    } catch {
      try { el.value = text; } catch { return false; }
    } finally {
      if (touchMode) {
        try {
          if (oldInputMode === null || oldInputMode === undefined) el.removeAttribute?.("inputmode");
          else el.setAttribute?.("inputmode", oldInputMode);
          try { el.readOnly = oldReadOnly; } catch (_) {}
          if (!hadReadOnly) el.removeAttribute?.("readonly");
        } catch (_) {}
      }
    }

    try { el.setAttribute?.("value", text); } catch {}
    [
      new InputEvent("beforeinput", { bubbles: true, cancelable: true, data: text, inputType: "insertText" }),
      new InputEvent("input", { bubbles: true, cancelable: true, data: text, inputType: "insertText" }),
      new Event("change", { bubbles: true }),
      new KeyboardEvent("keyup", { bubbles: true, key: "0", code: "Digit0" }),
      new Event("blur", { bubbles: true }),
    ].forEach((evt) => { try { el.dispatchEvent(evt); } catch {} });

    if (touchMode) {
      try { el.blur?.(); } catch (_) {}
      try { document.activeElement?.blur?.(); } catch (_) {}
    }

    return true;
  }


  async function rwphPrefillPayAllMember(row) {
    const id = String(row?.id || "unknown");
    const name = row?.name || `Unknown ${id}`;
    const value = `${name} [${id}]`;
    const field = rwphFindPayAllMemberField();
    rwphPayAllLastMemberField = field || null;
    rwphPayAllActiveScope = rwphPayAllFieldScope(field) || null;
    const filled = rwphSetPayAllFieldValue(field, value);
    // Some Torn faction-control forms rebuild the amount input after a member is selected.
    // Keep the active form context tied to the latest selected member before the Amount button runs.
    await new Promise((resolve) => setTimeout(resolve, 120));
    if (field && rwphSendHelperVisible(field)) {
      rwphPayAllLastMemberField = field;
      rwphPayAllActiveScope = rwphPayAllFieldScope(field) || rwphPayAllActiveScope;
    }
    await copyText(value).catch(() => false);
    return { filled, value };
  }

  async function rwphPrefillPayAllAmount(row) {
    const value = String(rwphPayAllRowAmount(row));
    const scope = rwphPayAllActiveScope && rwphSendHelperVisible(rwphPayAllActiveScope) ? rwphPayAllActiveScope : null;
    let field = rwphFindPayAllAmountField(scope);
    let filled = rwphSetPayAllFieldValue(field, value);
    // Torn can render/re-render the amount field shortly after the member field/search selection changes.
    // Prefer the current member's active form/scope so the next payout does not land in an old amount box.
    for (let attempt = 0; !filled && attempt < 6; attempt++) {
      await new Promise((resolve) => setTimeout(resolve, 150));
      const retryScope = rwphPayAllActiveScope && rwphSendHelperVisible(rwphPayAllActiveScope) ? rwphPayAllActiveScope : null;
      field = rwphFindPayAllAmountField(retryScope);
      filled = rwphSetPayAllFieldValue(field, value);
    }
    if (filled && field) {
      try { field.dataset.rwphLastPayAllAmountAt = String(Date.now()); } catch (_) {}
    }
    await copyText(value).catch(() => false);
    return { filled, value };
  }

  function rwphDismissPayAllCopyPopupsSilently() {
    try {
      ["rwph-info-popup-panel-live", "rwphFullPopupPanelLive"].forEach((id) => {
        const el = document.getElementById(id);
        if (el) el.remove();
      });
      document.querySelectorAll?.(".rwph-info-popup-panel").forEach((el) => {
        try { el.remove(); } catch (_) {}
      });
    } catch (_) {}
  }

  function rwphHidePayAllActionButton(btn, label, stack) {
    if (!btn) return;
    btn.dataset.rwphOriginalText = label || btn.textContent || "Button";
    btn.textContent = btn.dataset.rwphOriginalText;
    btn.classList.add("rwph-pay-button-hidden");
    btn.hidden = true;
    btn.disabled = true;
    btn.setAttribute("aria-hidden", "true");
    try {
      btn.style.setProperty("display", "none", "important");
      btn.style.setProperty("visibility", "hidden", "important");
      btn.style.setProperty("pointer-events", "none", "important");
    } catch (_) {}
    if (stack) stack.push(btn);
  }

  function rwphUndoLastPayAllDisappear(stack) {
    if (!stack) return false;
    while (stack.length) {
      const btn = stack.pop();
      if (btn && btn.isConnected) {
        btn.classList.remove("rwph-pay-button-hidden");
        btn.hidden = false;
        btn.disabled = false;
        btn.removeAttribute("aria-hidden");
        try {
          btn.style.removeProperty("display");
          btn.style.removeProperty("visibility");
          btn.style.removeProperty("pointer-events");
        } catch (_) {}
        btn.textContent = btn.dataset.rwphOriginalText || btn.textContent || "Button";
        return true;
      }
    }
    return false;
  }

  function openPayAllCopyPanel(rows) {
    closePayAllCopyPanel();
    rwphEnsurePayAllStandaloneStyles();
    const safeRows = rows || [];
    const wrap = document.createElement("div");
    wrap.innerHTML = renderPayAllCopyPanelHtml(safeRows);
    const panel = wrap.firstElementChild;
    document.body.appendChild(panel);
    panel.hidden = false;
    rwphEnablePanelMoveResize(panel, ".rw-pay-all-head");
    rwphConsumeCrossTabPopup("payments", panel, 550);
    const payAllUndoStack = [];

    panel.addEventListener("click", async (e) => {
      const closeBtn = e.target.closest?.("[data-pay-all-close]");
      if (closeBtn) {
        closePayAllCopyPanel();
        return;
      }

      const undoBtn = e.target.closest?.("[data-pay-all-undo]");
      if (undoBtn) {
        rwphUndoLastPayAllDisappear(payAllUndoStack);
        return;
      }

      const nameBtn = e.target.closest?.("[data-pay-copy-name]");
      if (nameBtn) {
        rwphDismissPayAllCopyPopupsSilently();
        const row = safeRows[Number(nameBtn.dataset.payCopyName)] || {};
        const res = await rwphPrefillPayAllMember(row);
        // Copy buttons on the Payments Copy Panel are intentionally silent.
        rwphHidePayAllActionButton(nameBtn, "Name + ID", payAllUndoStack);
        return;
      }

      const amountBtn = e.target.closest?.("[data-pay-copy-amount]");
      if (amountBtn) {
        rwphDismissPayAllCopyPopupsSilently();
        const row = safeRows[Number(amountBtn.dataset.payCopyAmount)] || {};
        const res = await rwphPrefillPayAllAmount(row);
        // Copy buttons on the Payments Copy Panel are intentionally silent.
        rwphHidePayAllActionButton(amountBtn, "Amount", payAllUndoStack);
      }
    });
  }

  function rwphMaybeOpenPayAllFromFactionControlsUrl() {
    if (!(window.location.href || "").includes("/factions.php")) return false;
    if (!(window.location.href || "").includes("rwphPayAll=1")) return false;

    // In faction controls, show only the compact copy panel and keep the main RWPH panel closed.
    rwphSetPanelOpenState(false);
    setLauncherOpenState(false);
    const mainPanel = document.getElementById("rw-payout-helper");
    if (mainPanel) mainPanel.remove();

    setTimeout(() => {
      closePanel();
      const rows = rwphGetStoredPayAllRows();
      openPayAllCopyPanel(rows || []);
    }, 900);
    return true;
  }

  function buildPayoutText(rows) {
    return (rows || [])
      .map((r, index) => {
        const payout = rwphPayAllRowAmount(r);
        const id = String(r.id || "unknown");
        const name = r.name || `Unknown ${id}`;
        return `${index + 1}. ${name} [${id}] — ${money(payout)} — RW payout`;
      })
      .join("\n");
  }

  function safeNumber(value) {
    const n = Number(value || 0);
    return Number.isFinite(n) ? n : 0;
  }

  function percent(value, total) {
    const v = safeNumber(value);
    const t = safeNumber(total);
    if (!t) return "0.0%";
    return ((v / t) * 100).toFixed(1) + "%";
  }


  function buildTornFactionNewsletterModel(rows, summary) {
    const list = (rows || []).map((r, index) => ({
      rank: index + 1,
      id: String(r.id || "unknown"),
      name: r.name || `Unknown ${r.id || "unknown"}`,
      warHits: safeNumber(r.warHits ?? r.attacks),
      assists: safeNumber(r.assists),
      outsideHits: safeNumber(r.outsideHits),
      retaliationHits: safeNumber(r.retaliationHits),
      totalTrackedHits: safeNumber(r.totalTrackedHits),
      payableEvents: safeNumber(r.payableEvents),
      hospitalizingHits: safeNumber(r.hospitalizingHits),
      enemyFactionHospitalizingHits: safeNumber(r.enemyFactionHospitalizingHits),
      hospitalBonusPoints: safeNumber(r.hospitalBonusPoints),
      enemyFactionHospitalBonusPoints: safeNumber(r.enemyFactionHospitalBonusPoints),
      fairFightBonusPoints: safeNumber(r.fairFightBonusPoints),
      fairFightPerPayableHitBonus: safeNumber(r.fairFightPerPayableHitBonus),
      avgFairFight: safeNumber(r.avgFairFight || 1),
      points: safeNumber(r.points ?? r.weight),
      basePoints: safeNumber(r.basePoints),
      respect: safeNumber(r.respect),
      totalRespect: safeNumber(r.totalRespect ?? r.respect),
      weight: safeNumber(r.weight),
      payout: safeNumber(r.payout),
    }));
    const memberPayout = safeNumber(summary?.memberPayout ?? summary?.totalPayout) || list.reduce((sum, r) => sum + r.payout, 0);
    const overallTotalPayout = safeNumber(summary?.overallTotalPayout ?? summary?.totalPayoutDisplay) || memberPayout;
    const pointsMode = !!(summary?.pointsMode || summary?.calculationMode === "points");
    const totalWeight = pointsMode
      ? (safeNumber(summary?.totalPoints ?? summary?.totalWeight) || list.reduce((sum, r) => sum + r.points, 0))
      : (safeNumber(summary?.totalWeight) || list.reduce((sum, r) => sum + r.weight, 0));
    const perUnitAmount = safeNumber(summary?.perHitAmount ?? summary?.perWeightedHitAmount) || (totalWeight > 0 ? memberPayout / totalWeight : 0);
    const totalHits = safeNumber(summary?.totalWarHits ?? summary?.totalHits) || list.reduce((sum, r) => sum + r.warHits, 0);
    const totalAssists = safeNumber(summary?.totalAssists) || list.reduce((sum, r) => sum + r.assists, 0);
    const totalOutsideHits = safeNumber(summary?.totalOutsideHits) || list.reduce((sum, r) => sum + r.outsideHits, 0);
    const totalRetaliationHits = safeNumber(summary?.totalRetaliationHits) || list.reduce((sum, r) => sum + r.retaliationHits, 0);
    const totalTrackedHits = safeNumber(summary?.totalTrackedHits) || list.reduce((sum, r) => sum + r.totalTrackedHits, 0);
    const totalPayableEvents = safeNumber(summary?.calcMeta?.payableEvents) || list.reduce((sum, r) => sum + r.payableEvents, 0);
    const totalEnemyFactionHospitalizingHits = safeNumber(summary?.totalEnemyFactionHospitalizingHits) || list.reduce((sum, r) => sum + r.enemyFactionHospitalizingHits, 0);
    const totalEnemyFactionHospitalBonusPoints = safeNumber(summary?.totalEnemyFactionHospitalBonusPoints) || list.reduce((sum, r) => sum + r.enemyFactionHospitalBonusPoints, 0);
    const totalOwnFactionHospitalizingHits = safeNumber(summary?.totalHospitalizingHits ?? summary?.totalOwnFactionHospitalizingHits) || list.reduce((sum, r) => sum + r.hospitalizingHits, 0);
    const totalOwnFactionHospitalBonusPoints = safeNumber(summary?.totalHospitalBonusPoints ?? summary?.totalOwnFactionHospitalBonusPoints) || list.reduce((sum, r) => sum + r.hospitalBonusPoints, 0);
    const totalFairFightBonusPoints = safeNumber(summary?.totalFairFightBonusPoints) || list.reduce((sum, r) => sum + r.fairFightBonusPoints, 0);
    const totalRespect = safeNumber(summary?.totalRespect) || list.reduce((sum, r) => sum + r.totalRespect, 0);
    const totalPayRespect = safeNumber(summary?.payoutRespect ?? summary?.respect) || list.reduce((sum, r) => sum + r.respect, 0);
    const includeLeftFactionMembers = !!(summary?.includeLeftFactionMembers || summary?.calcMeta?.includeLeftFactionMembers || summary?.calcMeta?.options?.includeLeftFactionMembers || summary?.options?.includeLeftFactionMembers);
    const removedLeftFactionHits = includeLeftFactionMembers ? 0 : safeNumber(summary?.removedLeftFactionHits ?? summary?.calcMeta?.removedLeftFactionHits);
    const factionName = String(summary?.factionName || summary?.faction?.name || "Faction");
    const newsletterTitle = `${factionName} Payout Newsletter`;
    return {
      list, pointsMode, memberPayout, overallTotalPayout, totalWeight, perUnitAmount,
      totalHits, totalAssists, totalOutsideHits, totalRetaliationHits, totalTrackedHits,
      totalPayableEvents, totalEnemyFactionHospitalizingHits, totalEnemyFactionHospitalBonusPoints,
      totalOwnFactionHospitalizingHits, totalOwnFactionHospitalBonusPoints, totalFairFightBonusPoints,
      totalRespect, totalPayRespect, includeLeftFactionMembers, removedLeftFactionHits, factionName, newsletterTitle, generatedAt: new Date().toLocaleString(),
      attacksFetched: safeNumber(summary?.attacksFetched),
      nameCount: safeNumber(summary?.nameCount),
    };
  }

  function tornNewsletterTheme(themeKey) {
    const themes = {
      standard: { title: "Ranked War Payout Newsletter", accent: "#38bdf8", bg: "#111827", panel: "#1f2937", line: "#334155", text: "#f8fafc", muted: "#cbd5e1", icon: "⚔️" },
      cyber: { title: "Cyber Neon Payout Newsletter", accent: "#22d3ee", bg: "#08111f", panel: "#0f172a", line: "#155e75", text: "#ecfeff", muted: "#a5f3fc", icon: "🟦" },
      ledger: { title: "War Ledger Payout Newsletter", accent: "#94a3b8", bg: "#171717", panel: "#262626", line: "#525252", text: "#f5f5f5", muted: "#d4d4d4", icon: "📜" },
      crimson: { title: "Crimson Raid Payout Newsletter", accent: "#f97316", bg: "#1f0a0a", panel: "#2b1111", line: "#7f1d1d", text: "#fff7ed", muted: "#fed7aa", icon: "🟥" },
      gold: { title: "Victory Gold Payout Newsletter", accent: "#facc15", bg: "#1c1606", panel: "#2b2208", line: "#854d0e", text: "#fffbe6", muted: "#fef3c7", icon: "🏆" },
    };
    return themes[themeKey] || themes.standard;
  }

  function buildTornFactionNewsletterText(rows, summary, themeKey) {
    const m = buildTornFactionNewsletterModel(rows || [], summary || {});
    const t = tornNewsletterTheme(themeKey);
    const metricLabel = m.pointsMode ? "Points" : "Weight";
    const perUnitLabel = m.pointsMode ? "Per Point Amount" : "Per Hit Amount";
    const perUnitSub = m.pointsMode ? "per weighted Point" : "per weighted hit";
    const divider = "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━";
    const lines = [];
    lines.push(`${t.icon} ${m.newsletterTitle}`);
    lines.push(`Ranked War Payout Helper · ${m.factionName}`);
    lines.push(`Generated: ${m.generatedAt}`);
    lines.push(divider);
    lines.push(`Member Payout: ${money(m.memberPayout)}`);
    lines.push(`Total Payout: ${money(m.overallTotalPayout)}`);
    lines.push(`${perUnitLabel}: ${money(m.perUnitAmount)} ${perUnitSub}`);
    lines.push(`${metricLabel}: ${m.totalWeight.toFixed(2)} · Paid Members: ${m.list.length}`);
    lines.push(`War Hits: ${m.totalHits} · Assists: ${m.totalAssists} · Outside: ${m.totalOutsideHits} · Retals: ${m.totalRetaliationHits}`);
    if (!m.includeLeftFactionMembers) lines.push(`Removed Left-Member Hits: ${m.removedLeftFactionHits}`);
    if (m.pointsMode) {
      lines.push(`Own Hosp: ${m.totalOwnFactionHospitalizingHits} (${m.totalOwnFactionHospitalBonusPoints.toFixed(2)} pts) · Enemy Hosp: ${m.totalEnemyFactionHospitalizingHits} (${m.totalEnemyFactionHospitalBonusPoints.toFixed(2)} pts)`);
      lines.push(`Fair Bonus: ${m.totalFairFightBonusPoints.toFixed(2)} pts`);
    }
    lines.push(`Total Respect: ${m.totalRespect.toFixed(2)} · Pay Respect: ${m.totalPayRespect.toFixed(2)}`);
    lines.push(divider);
    lines.push(`# | Member | War | Ast | Out | Ret | Payable | ${metricLabel} | Payout | Share`);
    m.list.forEach((r) => {
      const metric = m.pointsMode ? r.points : r.weight;
      lines.push(`${r.rank}. ${r.name} [${r.id}] | W ${r.warHits} | A ${r.assists} | O ${r.outsideHits} | R ${r.retaliationHits} | P ${r.payableEvents} | ${metric.toFixed(2)} | ${money(r.payout)} | ${percent(r.payout, m.memberPayout)}`);
      if (m.pointsMode) {
        lines.push(`   Hosp: own ${r.hospitalizingHits}/${r.hospitalBonusPoints.toFixed(2)} pts · enemy ${r.enemyFactionHospitalizingHits}/${r.enemyFactionHospitalBonusPoints.toFixed(2)} pts · Avg FF ${r.avgFairFight.toFixed(2)}x · FF bonus ${r.fairFightBonusPoints.toFixed(2)}`);
      }
    });
    lines.push(divider);
    lines.push("Review payouts before sending faction funds. RWPH never sends money automatically.");
    return lines.join("\n");
  }

  function buildTornFactionNewsletterRichHtml(rows, summary, themeKey) {
    const m = buildTornFactionNewsletterModel(rows || [], summary || {});
    const t = tornNewsletterTheme(themeKey);
    const metricLabel = m.pointsMode ? "Points" : "Weight";
    const perUnitLabel = m.pointsMode ? "Per Point Amount" : "Per Hit Amount";
    const perUnitSub = m.pointsMode ? "per weighted Point" : "per weighted hit";
    const card = (label, value, sub = "") => `<td style="width:25%;padding:8px;"><div style="background:${t.panel};border:1px solid ${t.line};border-radius:10px;padding:10px;text-align:center;color:${t.text};"><div style="font-size:10px;letter-spacing:.6px;text-transform:uppercase;color:${t.muted};font-weight:800;">${esc(label)}</div><div style="font-size:16px;font-weight:900;color:${t.accent};margin-top:3px;">${esc(value)}</div>${sub ? `<div style="font-size:10px;color:${t.muted};margin-top:3px;">${esc(sub)}</div>` : ""}</div></td>`;
    const rowHtml = m.list.map((r, i) => {
      const metric = m.pointsMode ? r.points : r.weight;
      const even = i % 2 === 1;
      return `<tr style="background:${even ? "rgba(255,255,255,.04)" : "transparent"};">
        <td style="padding:8px;border-bottom:1px solid ${t.line};text-align:center;color:${t.text};">${r.rank}</td>
        <td style="padding:8px;border-bottom:1px solid ${t.line};color:${t.text};"><b>${esc(r.name)}</b><br><span style="color:${t.muted};font-size:11px;">${esc(r.id)}</span></td>
        <td style="padding:8px;border-bottom:1px solid ${t.line};text-align:center;color:${t.text};">${r.warHits}</td>
        <td style="padding:8px;border-bottom:1px solid ${t.line};text-align:center;color:${t.text};">${r.assists}</td>
        <td style="padding:8px;border-bottom:1px solid ${t.line};text-align:center;color:${t.text};">${r.outsideHits}</td>
        <td style="padding:8px;border-bottom:1px solid ${t.line};text-align:center;color:${t.text};">${r.retaliationHits}</td>
        <td style="padding:8px;border-bottom:1px solid ${t.line};text-align:center;color:${t.text};">${r.payableEvents}</td>
        <td style="padding:8px;border-bottom:1px solid ${t.line};text-align:center;color:${t.accent};font-weight:900;">${metric.toFixed(2)}</td>
        <td style="padding:8px;border-bottom:1px solid ${t.line};text-align:center;color:#86efac;font-weight:900;white-space:nowrap;">${money(r.payout)}</td>
        <td style="padding:8px;border-bottom:1px solid ${t.line};text-align:center;color:${t.text};white-space:nowrap;">${percent(r.payout, m.memberPayout)}</td>
      </tr>${m.pointsMode ? `<tr style="background:${even ? "rgba(255,255,255,.04)" : "transparent"};"><td></td><td colspan="9" style="padding:6px 8px 9px;border-bottom:1px solid ${t.line};color:${t.muted};font-size:11px;text-align:left;">Own hosp ${r.hospitalizingHits} / ${r.hospitalBonusPoints.toFixed(2)} pts · Enemy hosp ${r.enemyFactionHospitalizingHits} / ${r.enemyFactionHospitalBonusPoints.toFixed(2)} pts · Avg FF ${r.avgFairFight.toFixed(2)}x · FF bonus ${r.fairFightBonusPoints.toFixed(2)}</td></tr>` : ""}`;
    }).join("");
    return `<div style="background:${t.bg};color:${t.text};font-family:Arial,Helvetica,sans-serif;padding:16px;border:1px solid ${t.line};border-radius:14px;max-width:1100px;margin:0 auto;text-align:center;">
      <div style="background:${t.panel};border:1px solid ${t.line};border-radius:14px;padding:14px;margin-bottom:12px;">
        <div style="font-size:12px;color:${t.muted};font-weight:900;letter-spacing:1px;text-transform:uppercase;">Ranked War Payout Helper · ${esc(m.factionName)}</div>
        <div style="font-size:24px;font-weight:900;color:${t.text};margin:4px 0;">${esc(t.icon)} ${esc(m.newsletterTitle)}</div>
        <div style="font-size:12px;color:${t.muted};">Generated ${esc(m.generatedAt)} · ${m.list.length} paid members</div>
      </div>
      <table style="width:100%;border-collapse:separate;border-spacing:6px;margin-bottom:10px;"><tbody>
        <tr>${card("Member Payout", money(m.memberPayout), `${m.list.length} members paid`)}${card("Total Payout", money(m.overallTotalPayout), "full payout record")}${card(perUnitLabel, money(m.perUnitAmount), perUnitSub)}${card(metricLabel, m.totalWeight.toFixed(2), m.pointsMode ? "total points" : "total weight")}</tr>
        <tr>${card("War Hits", String(m.totalHits), `${m.totalAssists} assists`)}${card("Outside Hits", String(m.totalOutsideHits), `${m.totalRetaliationHits} retals`)}${card("Tracked", String(m.totalTrackedHits), `${m.totalPayableEvents} payable`)}${card("Total Respect", m.totalRespect.toFixed(2), "ranked war report")}</tr>
        ${!m.includeLeftFactionMembers ? `<tr>${card("Removed Left-Member Hits", String(m.removedLeftFactionHits), "excluded former-member hits")}${card("Paid Members", String(m.list.length), "current faction results")}${card("Fetched Attacks", String(m.attacksFetched), "server calculation")}${card("Names Loaded", String(m.nameCount), "member matches")}</tr>` : ""}
        ${m.pointsMode ? `<tr>${card("Own Hosp", String(m.totalOwnFactionHospitalizingHits), `${m.totalOwnFactionHospitalBonusPoints.toFixed(2)} bonus pts`)}${card("Enemy Hosp", String(m.totalEnemyFactionHospitalizingHits), `${m.totalEnemyFactionHospitalBonusPoints.toFixed(2)} bonus pts`)}${card("Fair Bonus", m.totalFairFightBonusPoints.toFixed(2), "Avg FF bonus")}${card("Pay Respect", m.totalPayRespect.toFixed(2), "payable respect")}</tr>` : ""}
      </tbody></table>
      <div style="overflow-x:auto;border:1px solid ${t.line};border-radius:12px;background:${t.panel};">
        <table style="width:100%;min-width:820px;border-collapse:collapse;">
          <thead><tr style="background:${t.line};">
            <th style="padding:8px;color:${t.text};font-size:11px;">#</th><th style="padding:8px;color:${t.text};font-size:11px;text-align:left;">Member</th><th style="padding:8px;color:${t.text};font-size:11px;">War</th><th style="padding:8px;color:${t.text};font-size:11px;">Ast</th><th style="padding:8px;color:${t.text};font-size:11px;">Out</th><th style="padding:8px;color:${t.text};font-size:11px;">Ret</th><th style="padding:8px;color:${t.text};font-size:11px;">Payable</th><th style="padding:8px;color:${t.text};font-size:11px;">${esc(metricLabel)}</th><th style="padding:8px;color:${t.text};font-size:11px;">Payout</th><th style="padding:8px;color:${t.text};font-size:11px;">Share</th>
          </tr></thead><tbody>${rowHtml}</tbody>
        </table>
      </div>
      <div style="padding:12px 4px 0;color:${t.muted};font-size:11px;font-weight:800;">Review payouts before sending faction funds. RWPH never sends money automatically.</div>
    </div>`;
  }

  function buildTornFactionNewsletterBundle(rows, summary, themeKey) {
    return {
      html: buildTornFactionNewsletterRichHtml(rows || [], summary || {}, themeKey),
      text: buildTornFactionNewsletterText(rows || [], summary || {}, themeKey),
    };
  }


